const defaults = {
  systemProfile: 'eSpire280',
  crdMode: 'no-export',
  scheduledControlEnabled: false,
  minSoc: 0.1,
  maxSoc: 0.95,
  socLow: 0.3,
  socLowRecover: 0.22,
  socHigh: 0.95,
  socHighRecover: 0.92,
  forceGridChargeSoc: 0.15,
  forceGridChargeMinCellVoltageV: 2.95,
  forceGridChargeKw: 10,
  powerHeadroomKw: 2,
  commandRampKwPerSec: 25,
  generatorControlType: 'SEL',
  generatorChargeKw: 30
};
const cfg = Object.assign({}, defaults, flow.get('labConfig') || {});
if (msg.topic && msg.topic !== 'init') {
  cfg[msg.topic] = msg.payload;
}
cfg.scheduledControlEnabled = cfg.scheduledControlEnabled === true || cfg.scheduledControlEnabled === 'true';
cfg.minSoc = Number(cfg.minSoc);
cfg.maxSoc = Number(cfg.maxSoc);
cfg.socLow = Number(cfg.socLow);
cfg.socLowRecover = Number(cfg.socLowRecover);
cfg.socHigh = Number(cfg.socHigh);
cfg.socHighRecover = Number(cfg.socHighRecover);
cfg.forceGridChargeSoc = Number(cfg.forceGridChargeSoc);
cfg.forceGridChargeMinCellVoltageV = Number(cfg.forceGridChargeMinCellVoltageV);
cfg.forceGridChargeKw = Number(cfg.forceGridChargeKw);
cfg.powerHeadroomKw = Number(cfg.powerHeadroomKw);
cfg.commandRampKwPerSec = Number(cfg.commandRampKwPerSec);
cfg.generatorChargeKw = Number(cfg.generatorChargeKw);
flow.set('labConfig', cfg);
msg.payload = cfg;
return msg;

const lib = global.get('lib');
if (!lib || !lib.scheduler || !lib.coreControl) {
  node.error('global lib with scheduler/coreControl is unavailable', msg);
  return null;
}

const scenario = msg.payload || 'no-export-exporting';
if (scenario === 'reset') {
  flow.set('islandingState', { mode: 'idle' });
  flow.set('generatorState', { mode: 'idle' });
  msg.payload = { scenario, reset: true };
  return msg;
}

const cfg = Object.assign({
  systemProfile: 'eSpire280',
  crdMode: 'no-export',
  scheduledControlEnabled: false,
  minSoc: 0.1,
  maxSoc: 0.95,
  socLow: 0.3,
  socLowRecover: 0.22,
  socHigh: 0.95,
  socHighRecover: 0.92,
  forceGridChargeSoc: 0.15,
  forceGridChargeMinCellVoltageV: 2.95,
  forceGridChargeKw: 10,
  powerHeadroomKw: 2,
  commandRampKwPerSec: 25,
  generatorControlType: 'SEL',
  generatorChargeKw: 30
}, flow.get('labConfig') || {});

function siteConfig(overrides = {}) {
  const isMini = String(cfg.systemProfile).startsWith('MINI-');
  const base = {
    system: { systemProfile: cfg.systemProfile, controllerTimezone: 'America/Los_Angeles', nominal: { voltageVll: 480, frequencyHz: 60 } },
    network: { controller: { ip: '192.168.1.10', modbusServer: { ip: '192.168.1.20', port: 502 } } },
    operation: { mode: 'grid-tied', gridCode: 'IEEE1547-2018', crdMode: cfg.crdMode, scheduledControlEnabled: cfg.scheduledControlEnabled },
    battery: { minSoc: Number(cfg.minSoc), maxSoc: Number(cfg.maxSoc), socLow: Number(cfg.socLow), socLowRecover: Number(cfg.socLowRecover), socHigh: Number(cfg.socHigh), socHighRecover: Number(cfg.socHighRecover), forceGridChargeSoc: Number(cfg.forceGridChargeSoc), forceGridChargeMinCellVoltageV: Number(cfg.forceGridChargeMinCellVoltageV), forceGridChargeKw: Number(cfg.forceGridChargeKw), powerHeadroomKw: Number(cfg.powerHeadroomKw), commandRampKwPerSec: Number(cfg.commandRampKwPerSec) },
    pv: { acInverters: [], curtailmentMethod: null },
    metering: {
      meterType: 'eGauge-4015', modbusProfile: 'udt_eGauge_V1', ip: '192.168.1.88',
      reads: { pv: false, pvFromInverter: false, utility: true, load: true },
      calculations: {
        utilityPowerKw: { source: 'tag', tagID: 'Meter.POI_kW' },
        siteLoadKw: { source: 'tag', tagID: 'Meter.Load_Total_Power' },
        pvKw: { source: 'tag', tagID: 'Meter.PV_Total_Power' }
      }
    },
    generator: {
      maxKw: 50,
      chargeFromGenerator: true,
      chargeKwLimit: Number(cfg.generatorChargeKw),
      startSoc: 0.2,
      stopSoc: 0.9,
      controlType: cfg.generatorControlType
    }
  };
  if (!isMini) {
    base.pcs = { pcsDaisyChain: [1, 1], maxChargeKw: 250, maxDischargeKw: 250 };
    base.mbmu = { sbmuStrings: [2, 2] };
  }
  return Object.assign(base, overrides);
}

const plans = [
  { timed: [{ planID: 'may_off_peak', name: '5_off-peak_weekday_strategy', cron: '0 0 * MAY MON,TUE,WED,THU,FRI', duration: { unit: 'minutes', value: 959 }, start: '2026-05-01T00:00:00', until: '2026-05-31T15:59:00', strategy: { meter_rule: { discharge: { net_load_threshold: { value: 25.86, unit: 'kW' } }, charge: { net_load_threshold: { value: 19.4, unit: 'kW' } } } } }] },
  { timed: [{ planID: 'may_peak', name: '5_peak_weekday_strategy', cron: '0 16 * MAY MON,TUE,WED,THU,FRI', duration: { unit: 'minutes', value: 299 }, start: '2026-05-01T16:00:00', until: '2026-05-31T20:59:00', strategy: { meter_rule: { discharge: { net_load_threshold: { value: 5.16, unit: 'kW' } }, charge: { net_load_threshold: { value: -999999, unit: 'kW' } } } } }] },
  { planID: 'default', name: 'Default Command', default: true, cron: '0 0 * * *', strategy: { meter_rule: { discharge: { net_load_threshold: { value: 85, unit: 'kW' } }, charge: { net_load_threshold: { value: 0, unit: 'kW' } } } } }
];

let now = '2026-05-04T19:00:00.000Z';
let telemetry = { 'Meter.POI_kW': -18, 'Meter.Load_Total_Power': 30, 'Meter.PV_Total_Power': 42 };
let baseTelemetry = { soc: 0.62, gridStatus: 'normal', realtimeActivePowerKwRequest: 0 };
let localConfig = siteConfig();

if (scenario === 'scheduled-peak') {
  now = '2026-05-04T23:30:00.000Z';
  localConfig.operation.scheduledControlEnabled = true;
  localConfig.operation.crdMode = 'no-restriction';
  telemetry = { 'Meter.POI_kW': 30, 'Meter.Load_Total_Power': 50, 'Meter.PV_Total_Power': 0 };
}
if (scenario === 'machine-safety') {
  baseTelemetry = { soc: 0.62, gridStatus: 'normal', realtimeActivePowerKwRequest: -25, machineStatus: { bmsStatus: 1, maxCellVoltageV: 3.58, minCellVoltageV: 3.2 } };
  telemetry = { 'Meter.POI_kW': 0, 'Meter.Load_Total_Power': 30, 'Meter.PV_Total_Power': 0 };
}

const activePlan = lib.scheduler.matchActiveSchedulePlan(plans, { now, timezone: localConfig.system.controllerTimezone });
const schedule = activePlan ? lib.scheduler.scheduleOutputFromActivePlan(activePlan) : {};
const cycle = lib.coreControl.runUnifiedControlCycle(localConfig, { telemetry, baseTelemetry, schedule });

let generatorState = flow.get('generatorState') || { mode: 'idle' };
const generatorTelemetry = {
  nowMs: Date.now(),
  batterySoc: scenario === 'generator-running' ? 0.5 : baseTelemetry.soc,
  generatorRunning: scenario === 'generator-running',
  generatorAvailable: true
};
const generator = lib.coreControl.evaluateGeneratorSequencer(localConfig.generator, generatorTelemetry, generatorState);
flow.set('generatorState', generator.state);
const generatorWriterEnvelopes = localConfig.generator ? lib.coreControl.generatorCommandsToWriterEnvelopes(localConfig.generator, generator.commands, { remoteIoTopic: 'RemoteIO', remoteIoGeneratorTagID: 'RemoteIO.Generator_Start' }) : [];

let islandingState = flow.get('islandingState') || { mode: 'idle' };
let islandTelemetry = { nowMs: Date.now(), outageDetected: false, interlockClosed: false, pcsOnOff: 1, pcsGlobalState: 3, pcsRunMode: 0, gridWireConnection: 0 };
if (scenario === 'island-outage-step') {
  const step = Number(flow.get('islandStep') || 0) + 1;
  flow.set('islandStep', step);
  const snapshots = [
    { outageDetected: true },
    { outageDetected: true },
    { outageDetected: true, interlockClosed: false },
    { outageDetected: true, interlockClosed: true },
    { outageDetected: true, interlockClosed: true, pcsOnOff: 1, pcsGlobalState: 3 },
    { outageDetected: true, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 0, gridWireConnection: 0 },
    { outageDetected: true, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: true, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: true, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: true, interlockClosed: true, pcsOnOff: 1, pcsGlobalState: 6, pcsRunMode: 1, gridWireConnection: 1 }
  ];
  islandTelemetry = Object.assign({ nowMs: step * 250, outageDetected: true, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 1, gridWireConnection: 1 }, snapshots[Math.min(step - 1, snapshots.length - 1)]);
}
if (scenario === 'island-grid-return-step') {
  const step = Number(flow.get('gridStep') || 0) + 1;
  flow.set('gridStep', step);
  if (!islandingState || islandingState.mode === 'idle') islandingState = { mode: 'island-hold', phase: 'outage' };
  const snapshots = [
    { outageDetected: false, interlockClosed: true, pcsOnOff: 1, pcsGlobalState: 6, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: false, interlockClosed: true, pcsOnOff: 1, pcsGlobalState: 6, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: false, interlockClosed: true, pcsOnOff: 1, pcsGlobalState: 6, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: false, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 1, gridWireConnection: 1 },
    { outageDetected: false, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 0, gridWireConnection: 0 },
    { outageDetected: false, interlockClosed: true, pcsOnOff: 2, pcsGlobalState: 1, pcsRunMode: 0, gridWireConnection: 0 },
    { outageDetected: false, interlockClosed: true, pcsOnOff: 1, pcsGlobalState: 3, pcsRunMode: 0, gridWireConnection: 0 },
    { outageDetected: false, interlockClosed: false, pcsOnOff: 1, pcsGlobalState: 3, pcsRunMode: 0, gridWireConnection: 0 }
  ];
  islandTelemetry = Object.assign({ nowMs: step * 250 + 5000 }, snapshots[Math.min(step - 1, snapshots.length - 1)]);
}
const islanding = lib.coreControl.evaluateESpire280IslandingSequencer(islandTelemetry, islandingState, { waitMs: 100, retryMs: 200, modeDwellMs: 100, gridClearHoldMs: 100 });
flow.set('islandingState', islanding.state);
const islandingWriterEnvelopes = lib.coreControl.islandingCommandsToWriterEnvelopes(islanding.commands, { selTopic: localConfig.islanding?.device === 'SEL851' ? 'SEL851' : 'SEL751', interlockTagID: localConfig.islanding?.device === 'SEL851' ? 'SEL851.RB_1' : 'SEL751.RB_1' });

msg.payload = {
  scenario,
  labConfig: cfg,
  schedule: { selectedPlan: schedule.selectedPlan, strategy: schedule.strategy, constraints: schedule.constraints },
  unifiedControl: { telemetry: cycle.telemetry, command: cycle.command, pipeline: cycle.pipeline, writerEnvelopes: cycle.writerEnvelopes, diagnostics: cycle.diagnostics },
  generator: { telemetry: generatorTelemetry, state: generator.state, commands: generator.commands, reasons: generator.reasons, writerEnvelopes: generatorWriterEnvelopes },
  islanding: { telemetry: islandTelemetry, state: islanding.state, commands: islanding.commands, reasons: islanding.reasons, writerEnvelopes: islandingWriterEnvelopes }
};
return msg;
